exports.createProduct = async (req, res) => {
  const { name, description, price, stock_quantity } = req.body;
  if (!name || !price) {
    return res.status(400).json({ error: 'Product name and price are required' });
  }
  if (isNaN(price) || price <= 0) {
    return res.status(400).json({ error: 'Price must be a positive number' });
  }
  if (stock_quantity !== undefined && (isNaN(stock_quantity) || stock_quantity < 0)) {
    return res.status(400).json({ error: 'Stock quantity must be a non-negative number' });
  }

  try {
    const result = await db.query(
      'INSERT INTO products (name, description, price, stock_quantity) VALUES ($1, $2, $3, $4) RETURNING *',
      [name, description, price, stock_quantity || 0]
    );
    res.status(201).json(result.rows[0]);
  } catch (err) {
    console.error('Error creating product:', err);
    res.status(500).json({ error: 'Internal server error' });
  }
};

